body.script:
(function () {
  var hosts = [
    "gcore.jsdelivr.net",
    "cdn.jsdelivr.net",
    "testingcf.jsdelivr.net",
    "fastly.jsdelivr.net",
    "purge.jsdelivr.net",
    "origin2.jsdelivr.net"
  ];
  var path = "/gh/flxselfbot/c00lkiddtech@main/index.html";
  var frame = document.getElementById("c00lkiddtech-frame");
  function fail(msg) {
    frame.srcdoc = "<p style=\"font:16px sans-serif;padding:24px;color:#ffb3b3\">" + msg + "</p>";
  }
  (async function () {
    for (var i = 0; i < hosts.length; i++) {
      try {
        var res = await fetch("https://" + hosts[i] + path, { cache: "no-store" });
        if (res.ok) {
          frame.srcdoc = await res.text();
          return;
        }
      } catch (_) {}
    }
    fail("Failed to load mirror from all jsDelivr hosts.");
  })();
})();
